import React, { useState, useEffect } from 'react';
import axios from 'axios';

function Admin() {
  const [requests, setRequests] = useState([]);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [password, setPassword] = useState('');
  const adminPassword = "admin123";

  const fetchData = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/requests');
      setRequests(res.data);
    } catch (err) { 
      console.error("Error fetching data:", err); 
    }
  };

  useEffect(() => { 
    if (isLoggedIn) fetchData(); 
  }, [isLoggedIn]);

  const handleLogin = (e) => {
    e.preventDefault();
    if (password === adminPassword) setIsLoggedIn(true);
    else alert("Incorrect Password!");
  };

  const handleUpdate = async (id) => {
    const updatedStatus = document.getElementById(`status-${id}`).value;
    const updatedProgress = document.getElementById(`progress-${id}`).value;
    const updatedPayment = document.getElementById(`pay-${id}`).value;
    const updatedBudget = document.getElementById(`budget-${id}`).value;
    const updatedAdvance = document.getElementById(`advance-${id}`).value;

    try {
      await axios.put(`http://localhost:5000/api/update-status/${id}`, {
        status: updatedStatus,
        progress: updatedProgress,
        paymentStatus: updatedPayment,
        totalBudget: updatedBudget,
        advancePaid: updatedAdvance
      });
      alert("✅ Project Details Updated Successfully!");
      fetchData(); 
    } catch (err) {
      alert("❌ Update failed!");
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm("Are you sure you want to delete this project?")) {
      try {
        await axios.delete(`http://localhost:5000/api/delete-request/${id}`);
        fetchData();
      } catch (err) {
        alert("Delete failed!");
      }
    }
  };

  if (!isLoggedIn) {
    return (
      <div className="container d-flex justify-content-center align-items-center" style={{minHeight: '80vh'}}>
        <div className="card shadow-lg p-4 border-0 text-center" style={{width: '350px'}}>
          <h3 className="fw-bold mb-4">Admin Login</h3>
          <form onSubmit={handleLogin}>
            <input type="password" placeholder="Password" className="form-control mb-3 py-2 text-center" value={password} onChange={(e) => setPassword(e.target.value)} required />
            <button className="btn btn-primary w-100 fw-bold py-2 shadow">Login</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="container-fluid py-5 px-lg-5">
      <div className="d-flex justify-content-between align-items-center mb-4">
        <h2 className="fw-bold text-primary">Freelancer Admin Panel</h2>
        <button className="btn btn-sm btn-outline-danger shadow-sm" onClick={() => setIsLoggedIn(false)}>Logout</button>
      </div>

      <div className="table-responsive shadow rounded-4 bg-white p-2">
        <table className="table table-hover align-middle">
          <thead className="table-light text-secondary">
            <tr className="small text-uppercase">
              <th className="ps-3">Client & Service</th>
              <th>Financials (Budget / Advance)</th>
              <th>Payment Milestone</th>
              <th>Progress & Status</th>
              <th>Client Revisions</th>
              <th className="text-center">Action</th>
            </tr>
          </thead>
          <tbody>
            {requests.length > 0 ? requests.map((req) => {
              // Logic to determine payment milestone
              const isFullyPaid = req.totalBudget > 0 && req.advancePaid >= req.totalBudget;
              const hasAdvance = req.advancePaid > 0 && req.advancePaid < req.totalBudget;

              return (
                <tr key={req._id}>
                  {/* 1. Client Info */}
                  <td className="ps-3">
                    <div className="fw-bold">{req.fullName}</div>
                    <small className="text-muted">{req.serviceType}</small>
                  </td>

                  {/* 2. Fees Input */}
                  <td style={{width: '180px'}}>
                    <div className="input-group input-group-sm mb-1">
                      <span className="input-group-text">Total</span>
                      <input type="number" id={`budget-${req._id}`} className="form-control" defaultValue={req.totalBudget} />
                    </div>
                    <div className="input-group input-group-sm">
                      <span className="input-group-text bg-light text-success">Adv.</span>
                      <input type="number" id={`advance-${req._id}`} className="form-control" defaultValue={req.advancePaid} />
                    </div>
                  </td>

                  {/* 3. Payment Milestone Badges (NEW) */}
                  <td>
                    {isFullyPaid ? (
                      <span className="badge bg-success w-100 py-2">Settled (Full)</span>
                    ) : hasAdvance ? (
                      <span className="badge bg-info text-dark w-100 py-2">Advance Received</span>
                    ) : (
                      <span className="badge bg-light text-danger border w-100 py-2">No Payment</span>
                    )}
                    <div className="text-center mt-1">
                       <small className={`fw-bold ${req.paymentStatus === 'Paid' ? 'text-success' : 'text-danger'}`}>
                         Marked: {req.paymentStatus}
                       </small>
                    </div>
                  </td>

                  {/* 4. Progress & Status */}
                  <td>
                    <div className="d-flex gap-1 mb-1">
                        <input type="number" id={`progress-${req._id}`} className="form-control form-control-sm" defaultValue={req.progress} min="0" max="100" style={{width: '60px'}} />
                        <select id={`pay-${req._id}`} className="form-select form-select-sm" defaultValue={req.paymentStatus}>
                            <option value="Unpaid">Unpaid</option>
                            <option value="Paid">Paid</option>
                        </select>
                    </div>
                    <select id={`status-${req._id}`} className="form-select form-select-sm" defaultValue={req.status}>
                      <option value="Pending">Pending</option>
                      <option value="In Progress">In Progress</option>
                      <option value="Completed">Completed</option>
                    </select>
                  </td>

                  {/* 5. Revisions */}
                  <td style={{maxWidth: '180px'}}>
                    <div className="small text-muted border p-1 rounded bg-light" style={{height: '50px', overflowY: 'auto'}}>
                      {req.revisionsRequested || "No requests"}
                    </div>
                  </td>

                  {/* 6. Actions */}
                  <td className="text-center">
                    <div className="d-flex flex-column gap-1">
                      <button className="btn btn-success btn-sm fw-bold shadow-sm" onClick={() => handleUpdate(req._id)}>Save Changes</button>
                      <button className="btn btn-link btn-sm text-danger text-decoration-none" onClick={() => handleDelete(req._id)}>Delete</button>
                    </div>
                  </td>
                </tr>
              );
            }) : (
                <tr><td colSpan="6" className="text-center py-5 text-muted">No project requests found!</td></tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default Admin;
